/*
 * Rain OS v6 - Graphical UEFI Boot Manager
 * Target: Razer Blade 16 2025 (2560x1600 OLED)
 * Bilinear-smoothed font, high-FPS animations, modern utility panel
 */

#include <Uefi.h>
#include <Library/UefiLib.h>
#include <Library/UefiBootServicesTableLib.h>
#include <Library/UefiRuntimeServicesTableLib.h>
#include <Library/DevicePathLib.h>
#include <Library/MemoryAllocationLib.h>
#include <Library/BaseMemoryLib.h>
#include <Library/PrintLib.h>
#include <Protocol/LoadedImage.h>
#include <Protocol/GraphicsOutput.h>
#include <Protocol/SimpleFileSystem.h>

#define BOOT_COUNT          3
#define UTIL_COUNT          4
#define TIMEOUT_SECONDS    10

#define BLUR_RADIUS         8
#define BLUR_PASSES         2
#define BG_DARKEN          50

#define GLOW_ALPHA         45

#define SETTINGS_PANEL_RADIUS   30
#define SETTINGS_ROW_RADIUS     16
#define SETTINGS_BLUR_RADIUS     7
#define SETTINGS_BLUR_PASSES     3
#define SETTINGS_PANEL_TINT_A   146
#define SETTINGS_PANEL_HI_A      34
#define SETTINGS_PANEL_INNER_A   10

#define LOAD_HOLD      600000

#define ICON_KEY_THRESH    30
#define PREF_GOP_W      2560
#define PREF_GOP_H      1600
#define PIXELATE_ICON_SIZE    44

// Animation tick
// NOTE: UEFI GOP does not expose a reliable refresh-rate control, so we target a
// higher internal update rate to make fades and transitions feel smooth on high-Hz panels.
// If the platform can't keep up, the UI still works; it just updates less often.
#define TARGET_FPS      240
#define ANIM_INTERVAL   ((10000000ULL + (TARGET_FPS / 2)) / (TARGET_FPS)) // 100ns units

// Timings expressed in milliseconds, then converted to frames for TARGET_FPS.
#define MS_TO_FRAMES(ms)   ((UINTN)(((UINT64)(TARGET_FPS) * (UINT64)(ms) + 999ULL) / 1000ULL))

// Main menu fade timings tuned for smoother perceptual motion.
#define MENU_FADE_FRAMES  MS_TO_FRAMES(320)
// Footer: appears after a short delay and then remains visible until user input.
#define FOOTER_DELAY_F    MS_TO_FRAMES(420)
#define FOOTER_FADE_F     MS_TO_FRAMES(320)

// Light-bar slide
#define BAR_SLIDE_FRAMES  MS_TO_FRAMES(140)

// Icon size lerp divisor (higher = slower approach). Scale with FPS.
#define FPS_SCALE        ((TARGET_FPS + 59) / 60)
#define ICON_LERP_DENOM  (4 * FPS_SCALE)

/* Boot transition: fade-out 1.5 s, text fade-in 1 s */
#define BOOT_FADE_STEPS   18
#define BOOT_FADE_DELAY   10000
#define BOOT_FADEIN_STEPS 14
#define BOOT_FADEIN_DELAY 10000

typedef enum { MODE_MAIN = 0, MODE_UTILS } UI_MODE;

typedef struct {
  EFI_GRAPHICS_OUTPUT_BLT_PIXEL *Data;
  UINT32 W;
  UINT32 H;
} LOADED_IMAGE;

